// // This module implements a 6-bit shift register that shifts its contents to the right on each rising edge of the clock. When the reset signal is asserted high, the output register is cleared to zero. The most significant bit of the register is filled with the external input signal.
module top_module(input            clk,
              input            rst_n,
              input            in,
              output reg [5:0] q
              );always @(posedge clk, negedge rst_n) 
     if (!rst_n) 
       q = 0;
     else 
       q <= q << 1 | in;

endmodule
